// Validate and process pricing update data
const incomingData = $json;

// Required fields validation
const requiredFields = ['revenue_line', 'currency'];
const missingFields = requiredFields.filter(field => !incomingData[field]);

if (missingFields.length > 0) {
  return [{
    json: {
      error: true,
      message: `Missing required fields: ${missingFields.join(', ')}`,
      data: incomingData
    }
  }];
}

// Data type validation and conversion
const processedData = {
  revenue_line: String(incomingData.revenue_line).trim(),
  currency: String(incomingData.currency).toUpperCase().trim(),
  account_type: incomingData.account_type ? String(incomingData.account_type).trim() : 'N/A',
  competitors_count: incomingData.competitors_count ? parseInt(incomingData.competitors_count) : 0,

  // Fee statistics with proper decimal handling
  minimum_fee_mean: incomingData.minimum_fee_mean !== undefined && incomingData.minimum_fee_mean !== null ? parseFloat(incomingData.minimum_fee_mean) : null,
  minimum_fee_median: incomingData.minimum_fee_median !== undefined && incomingData.minimum_fee_median !== null ? parseFloat(incomingData.minimum_fee_median) : null,
  maximum_fee_mean: incomingData.maximum_fee_mean !== undefined && incomingData.maximum_fee_mean !== null ? parseFloat(incomingData.maximum_fee_mean) : null,
  maximum_fee_median: incomingData.maximum_fee_median !== undefined && incomingData.maximum_fee_median !== null ? parseFloat(incomingData.maximum_fee_median) : null,
  percentage_fee_mean: incomingData.percentage_fee_mean !== undefined && incomingData.percentage_fee_mean !== null ? parseFloat(incomingData.percentage_fee_mean) : null,
  percentage_fee_median: incomingData.percentage_fee_median !== undefined && incomingData.percentage_fee_median !== null ? parseFloat(incomingData.percentage_fee_median) : null,
  flat_fee_mean: incomingData.flat_fee_mean !== undefined && incomingData.flat_fee_mean !== null ? parseFloat(incomingData.flat_fee_mean) : null,
  flat_fee_median: incomingData.flat_fee_median !== undefined && incomingData.flat_fee_median !== null ? parseFloat(incomingData.flat_fee_median) : null,

  // Metadata
  updated_by: incomingData.updated_by || 'system',
  update_reason: incomingData.update_reason || 'Competitive analysis update',
  batch_id: incomingData.batch_id || null
};

// Business validation
if (processedData.minimum_fee_mean && processedData.maximum_fee_mean && 
    processedData.minimum_fee_mean > processedData.maximum_fee_mean) {
  return [{
    json: {
      error: true,
      message: 'Minimum fee cannot be greater than maximum fee',
      data: processedData
    }
  }];
}

if (processedData.percentage_fee_mean !== null && 
    (processedData.percentage_fee_mean < 0 || processedData.percentage_fee_mean > 100)) {
  return [{
    json: {
      error: true,
      message: 'Percentage fee must be between 0 and 100',
      data: processedData
    }
  }];
}

// Check for negative values in fee fields
const feeFields = ['minimum_fee_mean', 'minimum_fee_median', 'maximum_fee_mean', 'maximum_fee_median', 'flat_fee_mean', 'flat_fee_median'];
for (const field of feeFields) {
  if (processedData[field] !== null && processedData[field] < 0) {
    return [{
      json: {
        error: true,
        message: `${field} cannot be negative`,
        data: processedData
      }
    }];
  }
}

return [{
  json: {
    error: false,
    message: 'Data validation successful',
    data: processedData
  }
}];

// Create history record for audit trail
const existingRuleData = $input.first().json;
const newRuleData = $input.last().json;
const updateData = $node['Validate Pricing Data'].json.data;

// Handle array vs single object
const existingRule = Array.isArray(existingRuleData) ? existingRuleData[0] : existingRuleData;
const newRule = Array.isArray(newRuleData) ? newRuleData[0] : newRuleData;

if (!existingRule || Object.keys(existingRule).length === 0) {
  // New rule created
  return [{
    json: {
      change_type: 'CREATE',
      pricing_analysis_id: newRule.id,
      old_values: null,
      new_values: updateData,
      changed_by: updateData.updated_by,
      change_reason: `New pricing rule created: ${updateData.update_reason}`,
      revenue_line: newRule.revenue_line,
      currency: newRule.currency,
      account_type: newRule.account_type,
      changes: {}
    }
  }];
}

// Rule updated - compare changes
const changes = {};
const fields = [
  'competitors_count', 'minimum_fee_mean', 'minimum_fee_median',
  'maximum_fee_mean', 'maximum_fee_median', 'percentage_fee_mean',
  'percentage_fee_median', 'flat_fee_mean', 'flat_fee_median'
];

fields.forEach(field => {
  const oldVal = existingRule[field];
  const newVal = updateData[field];

  // Compare considering null values
  if (oldVal !== newVal && !(oldVal == null && newVal == null)) {
    changes[field] = {
      from: oldVal,
      to: newVal
    };
  }
});

return [{
  json: {
    change_type: Object.keys(changes).length > 0 ? 'UPDATE' : 'NO_CHANGE',
    pricing_analysis_id: existingRule.id,
    old_values: existingRule,
    new_values: updateData,
    changes: changes,
    changed_by: updateData.updated_by,
    change_reason: updateData.update_reason,
    revenue_line: existingRule.revenue_line,
    currency: existingRule.currency,
    account_type: existingRule.account_type
  }
}];

// Prepare history insert
const historyData = $json;

const escapeStr = (str) => String(str || '').replace(/'/g, "''");

const sqlInsert = `
INSERT INTO pricing_rules_history (
  pricing_analysis_id,
  old_values,
  new_values,
  changed_by,
  change_reason,
  change_type,
  changed_at
) VALUES (
  ${historyData.pricing_analysis_id},
  '${JSON.stringify(historyData.old_values).replace(/'/g, "''")}'::jsonb,
  '${JSON.stringify(historyData.new_values).replace(/'/g, "''")}'::jsonb,
  '${escapeStr(historyData.changed_by)}',
  '${escapeStr(historyData.change_reason)}',
  '${historyData.change_type}',
  NOW()
);`;

return [{
  json: {
    sql_query: sqlInsert,
    history_data: historyData
  }
}];

